import { DomainError } from '../../domain/errors';
import { WikiRepositoryPort } from '../ports/WikiRepositoryPort';

export interface RecordRiskInput {
  /** Where the risk was detected (e.g. `ingest`, `lint`, a command name). */
  source: string;
  /** Related artifact id (e.g. `QA-007`), optional. */
  id?: string;
  /** One-line description of the risk/contradiction. */
  conflict: string;
  /** ISO date (YYYY-MM-DD) for the row. */
  date: string;
}

export interface RecordRiskDeps {
  repo: WikiRepositoryPort;
  /** Stable content hash (e.g. sha256 hex). */
  hash: (content: string) => string;
}

export interface RecordRiskResult {
  /** Idempotency key derived from (source, id, conflict). */
  key: string;
  /** False when an identical row already existed. */
  created: boolean;
  path: string;
}

const RISK_FILE = 'risks.md';
const HEADER_MARK = '| Key |';
const TABLE_HEADER =
  '| Key | Date | Source | Related | Description | Status |\n' +
  '| --- | --- | --- | --- | --- | --- |\n';
const SCAFFOLD =
  '---\ntype: risk-register\ntags: [risks]\n---\n\n' +
  '# Risks & Contradictions\n\n' +
  'Maintained by `arch-wiki record-risk` — one row per detected risk or\n' +
  'contradiction, keyed by a content hash so re-recording is idempotent.\n\n' +
  TABLE_HEADER;

/** Markdown-table-safe single cell. */
function cell(value: string): string {
  return value.replace(/\r?\n/g, ' ').replace(/\|/g, '\\|').trim();
}

/**
 * Idempotently append a risk/contradiction row to `risks.md`. The row key hashes
 * (source, id, conflict); re-recording the same triple is a no-op. Used by
 * `ingest` for contradictions and available to lint triage.
 */
export async function recordRisk(
  input: RecordRiskInput,
  deps: RecordRiskDeps,
): Promise<RecordRiskResult> {
  const { repo, hash } = deps;
  const source = input.source.trim();
  const conflict = input.conflict.trim();
  if (!source) throw new DomainError('record-risk: missing source', 1);
  if (!conflict) throw new DomainError('record-risk: missing conflict', 1);
  const id = (input.id ?? '').trim();

  const key = hash(`${source}�${id}�${conflict}`).slice(0, 12);
  const row = `| ${key} | ${input.date} | ${cell(source)} | ${cell(id) || '—'} | ${cell(conflict)} | open |`;

  const exists = await repo.exists(RISK_FILE);
  if (!exists) {
    await repo.write(RISK_FILE, `${SCAFFOLD}${row}\n`);
    return { key, created: true, path: RISK_FILE };
  }

  const cur = await repo.read(RISK_FILE);
  if (cur.includes(`| ${key} |`)) {
    return { key, created: false, path: RISK_FILE };
  }
  const base = cur.length === 0 || cur.endsWith('\n') ? cur : `${cur}\n`;
  const next = cur.includes(HEADER_MARK) ? `${base}${row}\n` : `${base}\n${TABLE_HEADER}${row}\n`;
  await repo.write(RISK_FILE, next);
  return { key, created: true, path: RISK_FILE };
}
